import json
import statistics
from datetime import datetime
from typing import Any


def parse_ts(ts: str) -> datetime:
    return datetime.fromisoformat(ts.replace("Z", "+00:00"))


def compute_mttx(incidents: list[dict[str, Any]], severity: str = "SEV-1") -> dict[str, float]:
    """Compute p50 MTTD, MTTA, MTTR for incidents of a given severity (minutes)."""
    mttd_values, mtta_values, mttr_values = [], [], []

    for inc in incidents:
        if inc.get("severity") != severity:
            continue
        try:
            anomaly_ts = parse_ts(inc["anomaly_start"])
            alert_ts = parse_ts(inc["alert_fired"])
            ack_ts = parse_ts(inc["ic_acknowledged"])
            resolved_ts = parse_ts(inc["resolved"])
        except (KeyError, ValueError):
            continue  # skip incidents with missing timestamps

        mttd = (alert_ts - anomaly_ts).total_seconds() / 60
        mtta = (ack_ts - alert_ts).total_seconds() / 60
        mttr = (resolved_ts - anomaly_ts).total_seconds() / 60

        if mttd >= 0 and mtta >= 0 and mttr >= 0:
            mttd_values.append(mttd)
            mtta_values.append(mtta)
            mttr_values.append(mttr)

    def p50(vals: list[float]) -> float:
        return round(statistics.median(vals), 1) if vals else float("nan")

    return {
        "severity": severity,
        "sample_size": len(mttd_values),
        "p50_mttd_min": p50(mttd_values),
        "p50_mtta_min": p50(mtta_values),
        "p50_mttr_min": p50(mttr_values),
    }


def compare_to_targets(
    current: dict[str, float],
    targets: dict[str, float],
) -> None:
    """Print current vs target for each metric."""
    metrics = ["p50_mttd_min", "p50_mtta_min", "p50_mttr_min"]
    labels = {"p50_mttd_min": "MTTD", "p50_mtta_min": "MTTA", "p50_mttr_min": "MTTR"}
    print(f"{'Metric':<8} {'Current':>10} {'Target':>10} {'Gap':>10} {'Status':>10}")
    print("-" * 52)
    for m in metrics:
        cur = current.get(m, float("nan"))
        tgt = targets.get(m, float("nan"))
        gap = cur - tgt
        status = "ON TRACK" if gap <= 0 else f"BEHIND +{gap:.1f}m"
        print(f"{labels[m]:<8} {cur:>10.1f} {tgt:>10.1f} {gap:>10.1f} {status:>12}")


if __name__ == "__main__":
    with open("incidents.json") as f:
        incidents = json.load(f)

    current = compute_mttx(incidents, severity="SEV-1")
    print(f"Q3 baseline ({current['sample_size']} incidents):")

    # Q4 targets: 25% improvement on each metric
    targets = {
        "p50_mttd_min": current["p50_mttd_min"] * 0.75,
        "p50_mtta_min": current["p50_mtta_min"] * 0.75,
        "p50_mttr_min": current["p50_mttr_min"] * 0.75,
    }
    compare_to_targets(current, targets)
